import { createRoot } from "react-dom/client";
import App from "./App.tsx";
import "./index.css";

createRoot(document.getElementById("root")!).render(<App />);

import { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { Button } from '@/components/ui/button';
import {
    ArrowLeft,
    Megaphone,
    Play,
    Pause,
    Loader2,
    DollarSign,
    Eye,
    MousePointerClick,
    Target,
    BarChart3,
    MoreVertical,
    MapPin,
    Users,
    Globe,
    ChevronRight,
    TrendingUp,
    ShieldCheck,
    Zap,
    Settings,
    MoreHorizontal,
    Activity,
    Calendar,
    Sparkles
} from 'lucide-react';
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel,
    DropdownMenuSeparator,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { toast } from 'sonner';
import { motion, AnimatePresence } from 'framer-motion';

const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', {
        style: 'currency',
        currency: 'BRL',
    }).format(value);
};

const formatNumber = (value: number) => {
    if (value >= 1000000) return `${(value / 1000000).toFixed(2)}M`;
    if (value >= 1000) return `${(value / 1000).toFixed(2)}K`;
    return value.toLocaleString('pt-BR');
};

const formatPercent = (value: number) => {
    return `${value.toFixed(2)}%`;
};

const container = {
    hidden: { opacity: 0 },
    show: {
        opacity: 1,
        transition: {
            staggerChildren: 0.05
        }
    }
};

const item = {
    hidden: { opacity: 0, y: 15 },
    show: { opacity: 1, y: 0 }
};

export default function AdSetDetalhe() {
    const { id: campaignId, adsetId } = useParams<{ id: string; adsetId: string }>();
    const navigate = useNavigate();
    const queryClient = useQueryClient();

    const [isBudgetOpen, setIsBudgetOpen] = useState(false);
    const [newDailyBudget, setNewDailyBudget] = useState('');
    const [newLifetimeBudget, setNewLifetimeBudget] = useState('');

    const { data: adSet, isLoading } = useQuery({
        queryKey: ['adset', adsetId],
        queryFn: async () => {
            if (!adsetId) throw new Error('No adSet ID');

            const { data, error } = await supabase
                .from('ad_sets')
                .select('*, campaigns(name)')
                .eq('id', adsetId)
                .single();

            if (error) throw error;
            return data;
        },
        enabled: !!adsetId,
    });

    const { data: creatives } = useQuery({
        queryKey: ['adset-creatives', adsetId],
        queryFn: async () => {
            if (!adsetId) throw new Error('No adSet ID');

            const { data, error } = await supabase
                .from('creatives')
                .select('*')
                .eq('ad_set_id', adsetId)
                .order('impressions', { ascending: false });

            if (error) throw error;
            return data || [];
        },
        enabled: !!adsetId,
    });

    const adSetAction = useMutation({
        mutationFn: async ({ action, payload }: { action: string, payload?: any }) => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) throw new Error('No session');

            const response = await fetch(`${import.meta.env.VITE_SUPABASE_URL}/functions/v1/meta-adset-action`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${session.access_token}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    adset_id: adsetId,
                    action,
                    payload
                }),
            });

            if (!response.ok) {
                const error = await response.json();
                throw new Error(error.error || 'Failed to perform action');
            }

            return response.json();
        },
        onSuccess: (data, variables) => {
            toast.success(`Ação ${variables.action} realizada com sucesso`);
            queryClient.invalidateQueries({ queryKey: ['adset', adsetId] });
            setIsBudgetOpen(false);
        },
        onError: (error) => {
            toast.error(`Erro: ${error.message}`);
        }
    });

    const handleUpdateBudget = () => {
        const payload: any = {};
        if (newDailyBudget) payload.daily_budget = parseFloat(newDailyBudget.replace(',', '.')) * 100;
        if (newLifetimeBudget) payload.lifetime_budget = parseFloat(newLifetimeBudget.replace(',', '.')) * 100;

        if (Object.keys(payload).length === 0) return;
        adSetAction.mutate({ action: 'update_budget', payload });
    };

    const handleOpenBudget = () => {
        setNewDailyBudget(adSet?.daily_budget ? (adSet.daily_budget).toString() : '');
        setNewLifetimeBudget(adSet?.lifetime_budget ? (adSet.lifetime_budget).toString() : '');
        setIsBudgetOpen(true);
    };

    const renderTargeting = (targeting: any) => {
        if (!targeting) return (
            <div className="flex flex-col items-center justify-center p-8 border-2 border-dashed border-white/5 rounded-3xl opacity-40">
                <Globe className="w-8 h-8 mb-2" />
                <p className="text-[10px] font-black uppercase tracking-widest text-center">Segmentação Ampla Detectada</p>
            </div>
        );

        return (
            <div className="space-y-6">
                {targeting.geo_locations?.countries && (
                    <div className="bg-white/[0.02] border border-white/5 p-4 rounded-2xl group hover:border-ch-orange/30 transition-all">
                        <div className="flex items-center gap-2 mb-2">
                            <MapPin className="w-3.5 h-3.5 text-ch-orange" />
                            <span className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest">Geolocalização</span>
                        </div>
                        <span className="text-sm font-black text-ch-white uppercase tracking-tight italic">
                            {targeting.geo_locations.countries.join(', ')}
                        </span>
                    </div>
                )}

                <div className="bg-white/[0.02] border border-white/5 p-4 rounded-2xl group hover:border-ch-orange/30 transition-all">
                    <div className="flex items-center gap-2 mb-2">
                        <Users className="w-3.5 h-3.5 text-ch-orange" />
                        <span className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest">Demográfico Principal</span>
                    </div>
                    <span className="text-sm font-black text-ch-white italic tracking-widest tabular-nums">
                        IDADE: {targeting.age_min || 18} - {targeting.age_max || 65}+ ANOS
                    </span>
                </div>

                {targeting.flexible_spec && (
                    <div className="bg-white/[0.02] border border-white/5 p-4 rounded-2xl">
                        <div className="flex items-center gap-2 mb-4">
                            <Target className="w-3.5 h-3.5 text-ch-orange" />
                            <span className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest">Matriz de Interesses</span>
                        </div>
                        <div className="flex flex-wrap gap-2">
                            {targeting.flexible_spec.flatMap((spec: any) =>
                                spec.interests?.map((interest: any) => (
                                    <span key={interest.id} className="bg-ch-orange/5 text-ch-orange px-3 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest border border-ch-orange/10 hover:bg-ch-orange/10 transition-all">
                                        {interest.name}
                                    </span>
                                ))
                            )}
                        </div>
                    </div>
                )}
            </div>
        );
    };

    const getStatusBadge = (status: string) => {
        const config: Record<string, { label: string, color: string, icon: any }> = {
            active: { label: 'Em Veiculação', color: 'emerald-500', icon: Play },
            paused: { label: 'Suspenso', color: 'amber-500', icon: Pause },
            deleted: { label: 'Excluído', color: 'rose-500', icon: Trash2 },
            archived: { label: 'Arquivado', color: 'ch-text-dimmed', icon: Archive },
        };
        const cfg = config[status] || config.paused;
        const Icon = cfg.icon;
        return (
            <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest bg-${cfg.color}/10 text-${cfg.color} border border-${cfg.color}/20 shadow-sm`}>
                <Icon className="w-3.5 h-3.5" />
                {cfg.label}
            </span>
        );
    };

    if (isLoading || !adSet) {
        return (
            <div className="p-6 flex flex-col items-center justify-center min-h-[500px] gap-4">
                <Loader2 className="w-10 h-10 animate-spin text-ch-orange opacity-40" />
                <p className="text-[10px] font-black text-ch-text-dimmed uppercase tracking-widest">Consolidando dados do conjunto...</p>
            </div>
        );
    }

    const ctr = adSet.impressions > 0 ? (adSet.clicks / adSet.impressions) * 100 : 0;
    const cpc = adSet.clicks > 0 ? adSet.spend / adSet.clicks : 0;

    return (
        <motion.div
            initial="hidden"
            animate="show"
            variants={container}
            className="p-6 space-y-8"
        >
            {/* Header */}
            <motion.div variants={item} className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-5">
                    <Button
                        variant="outline"
                        size="icon"
                        onClick={() => navigate(`/campanhas/${campaignId}`)}
                        className="h-12 w-12 bg-ch-dark-gray/40 border-white/5 hover:bg-ch-orange/10 hover:text-ch-orange transition-all duration-300 rounded-2xl group"
                    >
                        <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                    </Button>
                    <div>
                        <div className="flex items-center gap-2 text-[10px] font-black text-ch-text-muted mb-1 uppercase tracking-widest">
                            <span className="hover:text-ch-orange transition-colors cursor-pointer" onClick={() => navigate(`/campanhas/${campaignId}`)}>Campanha</span>
                            <ChevronRight className="w-3 h-3 opacity-30" />
                            <span className="text-ch-white">Estrutura de Público</span>
                        </div>
                        <h1 className="text-3xl font-black text-ch-white tracking-tight uppercase italic">{adSet.name}</h1>
                        <div className="flex items-center gap-3 mt-1.5">
                            <span className="text-[11px] font-bold text-ch-text-dimmed tracking-wider">REF: {adSet.external_id}</span>
                            <span className="w-1 h-1 rounded-full bg-white/10" />
                            <span className="text-[11px] font-black text-ch-text-muted uppercase tracking-widest">{adSet.optimization_goal?.replace(/_/g, ' ') || 'Conversões'}</span>
                        </div>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/5 border border-emerald-500/10 rounded-xl mr-2">
                        <ShieldCheck className="w-4 h-4 text-emerald-500" />
                        <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">Público Qualificado</span>
                    </div>

                    <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                            <Button className="bg-ch-white hover:bg-ch-orange text-ch-black font-black uppercase tracking-widest rounded-xl transition-all h-12 px-6 shadow-xl group">
                                Ações de Gestão <Settings className="ml-2 h-4 w-4 group-hover:rotate-45 transition-transform" />
                            </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end" className="bg-ch-black-soft border-white/10 w-60">
                            <DropdownMenuLabel className="text-[10px] font-black uppercase tracking-widest text-ch-text-dimmed">Centro de Operações</DropdownMenuLabel>
                            {adSet.status === 'active' ? (
                                <DropdownMenuItem onClick={() => adSetAction.mutate({ action: 'pause' })} className="py-3 cursor-pointer">
                                    <Pause className="mr-3 h-4 w-4 text-amber-500" /> <span className="font-bold">Congelar Conjunto</span>
                                </DropdownMenuItem>
                            ) : (
                                <DropdownMenuItem onClick={() => adSetAction.mutate({ action: 'activate' })} className="py-3 cursor-pointer">
                                    <Play className="mr-3 h-4 w-4 text-emerald-500" /> <span className="font-bold">Descongelar Conjunto</span>
                                </DropdownMenuItem>
                            )}
                            <DropdownMenuSeparator className="bg-white/5" />
                            <DropdownMenuItem onClick={handleOpenBudget} className="py-3 cursor-pointer">
                                <DollarSign className="mr-3 h-4 w-4 text-teal-400" /> Calibrar Orçamento
                            </DropdownMenuItem>
                            <DropdownMenuSeparator className="bg-white/5" />
                            <DropdownMenuItem className="py-3 text-rose-500 opacity-50 cursor-not-allowed">
                                <Trash2 className="mr-3 h-4 w-4" /> Descartar Público
                            </DropdownMenuItem>
                        </DropdownMenuContent>
                    </DropdownMenu>
                </div>
            </motion.div>

            {/* Metrics Snapshot */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {[
                    { label: 'Alcance Único', value: formatNumber(adSet.impressions || 0), icon: Eye, color: 'blue-400' },
                    { label: 'Interações', value: formatNumber(adSet.clicks || 0), icon: MousePointerClick, color: 'indigo-400' },
                    { label: 'CTR Médio', value: formatPercent(ctr), icon: TrendingUp, color: 'ch-orange' },
                    { label: 'Investimento', value: formatCurrency(adSet.spend || 0), icon: DollarSign, color: 'emerald-400' },
                ].map((metric) => (
                    <motion.div key={metric.label} variants={item} whileHover={{ y: -3 }} className="glass-card rounded-3xl p-6 border-white/5 shadow-xl group">
                        <div className="flex items-center gap-3 mb-4">
                            <div className={`p-2 bg-${metric.color}/10 rounded-xl`}>
                                <metric.icon className={`w-4 h-4 text-${metric.color}`} />
                            </div>
                            <span className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">{metric.label}</span>
                        </div>
                        <p className="text-2xl font-black text-ch-white tracking-tighter tabular-nums group-hover:text-ch-orange transition-colors">{metric.value}</p>
                    </motion.div>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Main Content Side */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Active Creatives */}
                    <motion.div variants={item} className="glass rounded-[2rem] overflow-hidden border-white/5 shadow-2xl">
                        <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.01]">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-ch-orange/10 rounded-xl">
                                    <Sparkles className="w-5 h-5 text-ch-orange" />
                                </div>
                                <h2 className="text-lg font-black text-ch-white uppercase tracking-tight">Ativos em Rotação ({creatives?.length || 0})</h2>
                            </div>
                        </div>
                        <div className="divide-y divide-white/5">
                            {creatives?.map((creative: any) => (
                                <div key={creative.id} className="p-6 flex flex-col md:flex-row md:items-center justify-between hover:bg-white/[0.02] transition-all group cursor-pointer" onClick={() => navigate(`/criativos/${creative.id}`)}>
                                    <div className="flex items-center gap-5">
                                        <div className="w-16 h-16 bg-ch-black border border-white/10 rounded-2xl overflow-hidden group-hover:border-ch-orange/30 transition-all shadow-lg shadow-black/40">
                                            {creative.image_url ? (
                                                <img src={creative.image_url} alt="" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
                                            ) : (
                                                <div className="w-full h-full flex items-center justify-center bg-white/[0.02]">
                                                    <Megaphone className="w-6 h-6 text-ch-text-dimmed opacity-20" />
                                                </div>
                                            )}
                                        </div>
                                        <div>
                                            <p className="font-black text-ch-white group-hover:text-ch-orange transition-colors uppercase tracking-tight line-clamp-1">{creative.name}</p>
                                            <p className="text-[10px] text-ch-text-muted font-bold mt-1 uppercase tracking-[0.15em] line-clamp-1 italic">{creative.headline || 'Sem Headline Administrativa'}</p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-10 mt-6 md:mt-0">
                                        <div className="text-right">
                                            <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1">CTR do Ativo</p>
                                            <p className="text-sm font-black text-ch-orange tabular-nums italic">
                                                {creative.impressions > 0 ? ((creative.clicks / creative.impressions) * 100).toFixed(2) : 0}%
                                            </p>
                                        </div>
                                        <div className="text-right">
                                            <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-1">Custo Médio</p>
                                            <p className="text-sm font-black text-emerald-400 tabular-nums">
                                                {creative.clicks > 0 ? formatCurrency(creative.spend / creative.clicks) : 'R$ 0,00'}
                                            </p>
                                        </div>
                                        <ChevronRight className="w-5 h-5 text-ch-text-dimmed group-hover:text-ch-orange group-hover:translate-x-1 transition-all" />
                                    </div>
                                </div>
                            ))}
                        </div>
                    </motion.div>
                </div>

                {/* Sidebar Side */}
                <div className="space-y-8">
                    {/* Targeting Specs */}
                    <motion.div variants={item} className="glass-premium rounded-[2.5rem] p-8 border-white/10 shadow-2xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-12 opacity-[0.03] pointer-events-none group-hover:opacity-[0.08] transition-all duration-500">
                            <Globe className="w-48 h-48" />
                        </div>
                        <h2 className="text-lg font-black text-ch-white uppercase tracking-tight mb-8 flex items-center gap-3">
                            <div className="w-1.5 h-6 bg-ch-orange rounded-full" /> Setup de Público
                        </h2>
                        {renderTargeting(adSet.targeting)}
                    </motion.div>

                    {/* Budget & Bid Side Card */}
                    <motion.div variants={item} className="glass rounded-[2rem] p-8 border-white/5 relative overflow-hidden shadow-2xl">
                        <h2 className="text-sm font-black text-ch-white uppercase tracking-[0.2em] mb-8 border-l-2 border-ch-orange pl-4">Parâmetros Financeiros</h2>
                        <div className="space-y-8">
                            <div>
                                <p className="text-[9px] font-black text-ch-text-dimmed uppercase tracking-widest mb-2">Orçamento Atual</p>
                                <div className="flex items-center justify-between bg-white/[0.02] border border-white/5 p-4 rounded-2xl group hover:border-emerald-500/30 transition-all">
                                    <span className="text-[10px] font-bold text-ch-text-muted">DIÁRIO</span>
                                    <span className="text-xl font-black text-ch-white tabular-nums">
                                        {adSet.daily_budget ? formatCurrency(adSet.daily_budget) : '-'}
                                    </span>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-6 pt-4 border-t border-white/5">
                                <div>
                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest mb-2">Estratégia</p>
                                    <p className="text-xs font-black text-ch-white uppercase italic tracking-tighter">
                                        {adSet.bid_strategy?.replace(/_/g, ' ') || 'MENOR CUSTO'}
                                    </p>
                                </div>
                                <div>
                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest mb-2">Janela Atrib.</p>
                                    <p className="text-xs font-black text-ch-white uppercase italic tracking-tighter">7 DIAS CLIQUE</p>
                                </div>
                                <div>
                                    <p className="text-[9px] font-black text-ch-text-muted uppercase tracking-widest mb-2">Meta de Otimização</p>
                                    <p className="text-xs font-black text-ch-white uppercase italic tracking-tighter">
                                        {(adSet as any).optimization_goal?.replace(/_/g, ' ') || 'CONVERSÃO'}
                                    </p>
                                </div>
                            </div>
                        </div>
                    </motion.div>

                    {/* Information Node */}
                    <motion.div variants={item} className="glass rounded-[2rem] p-8 border-white/5 shadow-2xl">
                        <h2 className="text-sm font-black text-ch-white uppercase tracking-[0.2em] mb-6">Nódulo de Dados</h2>
                        <div className="space-y-4">
                            {[
                                { label: 'Status API', value: adSet.status, color: 'emerald-500' },
                                { label: 'Data de Início', value: adSet.start_time ? format(new Date(adSet.start_time), 'dd/MM/yyyy') : 'Contínuo', color: 'ch-text-dimmed' },
                                { label: 'Duração', value: 'Vitalício', color: 'ch-text-dimmed' },
                            ].map((row) => (
                                <div key={row.label} className="flex justify-between items-center py-2">
                                    <span className="text-[10px] font-black text-ch-text-muted uppercase tracking-widest">{row.label}</span>
                                    <span className={`text-[11px] font-black text-${row.color} uppercase tracking-tight italic`}>{row.value}</span>
                                </div>
                            ))}
                        </div>
                    </motion.div>
                </div>
            </div>

            {/* Calibration Dialog */}
            <AnimatePresence>
                {isBudgetOpen && (
                    <Dialog open={isBudgetOpen} onOpenChange={setIsBudgetOpen}>
                        <DialogContent className="bg-ch-black-soft border-white/10 shadow-2xl rounded-[2.5rem] p-8 max-w-lg">
                            <DialogHeader>
                                <DialogTitle className="text-2xl font-black text-ch-white uppercase tracking-tight italic">Calibração Financeira</DialogTitle>
                                <DialogDescription className="text-ch-text-dimmed font-medium mt-2">
                                    Otimize os limites de gasto deste conjunto para melhorar o desempenho da IA.
                                </DialogDescription>
                            </DialogHeader>
                            <div className="grid gap-8 py-10">
                                <div className="space-y-4">
                                    <Label htmlFor="daily" className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted ml-1">INVESTIMENTO DIÁRIO (R$)</Label>
                                    <div className="relative">
                                        <DollarSign className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-ch-orange" />
                                        <Input
                                            id="daily"
                                            value={newDailyBudget}
                                            onChange={(e) => setNewDailyBudget(e.target.value)}
                                            className="bg-ch-dark-gray/40 border-white/10 text-ch-white h-16 pl-14 font-black tabular-nums text-xl focus:border-emerald-500/50 rounded-2xl transition-all"
                                            placeholder="0,00"
                                        />
                                    </div>
                                </div>
                                <div className="space-y-4">
                                    <Label htmlFor="lifetime" className="text-[10px] font-black uppercase tracking-widest text-ch-text-muted ml-1">INVESTIMENTO VITALÍCIO (R$)</Label>
                                    <div className="relative">
                                        <Activity className="absolute left-5 top-1/2 -translate-y-1/2 w-5 h-5 text-ch-text-dimmed" />
                                        <Input
                                            id="lifetime"
                                            value={newLifetimeBudget}
                                            onChange={(e) => setNewLifetimeBudget(e.target.value)}
                                            className="bg-ch-dark-gray/40 border-white/10 text-ch-white h-16 pl-14 font-black tabular-nums text-xl focus:border-blue-500/50 rounded-2xl transition-all"
                                            placeholder="NÃO DEFINIDO"
                                        />
                                    </div>
                                </div>
                            </div>
                            <DialogFooter className="gap-4">
                                <Button variant="outline" onClick={() => setIsBudgetOpen(false)} className="rounded-2xl font-black uppercase text-[11px] tracking-widest h-14 px-8 border-white/5 hover:bg-white/5 transition-all">Descartar</Button>
                                <Button onClick={handleUpdateBudget} disabled={adSetAction.isPending} className="bg-ch-orange hover:bg-ch-orange-hover text-ch-black font-black uppercase text-[11px] tracking-widest px-10 rounded-2xl h-14 shadow-xl shadow-ch-orange/20 transition-all">
                                    {adSetAction.isPending ? <Loader2 className="w-5 h-5 animate-spin" /> : 'Confirmar no Meta Ads'}
                                </Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                )}
            </AnimatePresence>
        </motion.div>
    );
}

